import React, { useState } from 'react';

const EditOutflow = ({ outflow, handleUpdate, locations, materials, vendors}) => {
  
  
  const [editedOutflow, setEditedOutflow] = useState({ ...outflow });
  const handleChange = (e) => {
    const { name, value } = e.target;
    setEditedOutflow((prevOutflow) => ({
      ...prevOutflow,
      [name]: value,
    }))
  }

  const handleSave = () => {
    handleUpdate(editedOutflow);
  }

 
  const hideWidthAndLotNo =
  materials.find((material) => material.matid === editedOutflow.materialid)?.extras !== 1;


  return (
    <div className="edit-outflow">
      <h2>Edit Outflow</h2>
      <div>
      <label>
        Location:
        <select name="location" value={editedOutflow.locationname} onChange={handleChange} required>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.locationname}>
              {location.locationname}
            </option>
          ))}
        </select>
      </label>
      </div>      
      {hideWidthAndLotNo ? null : (
        <>
          <div>
            <label>
              Width:
              <input type="text" name="width" value={editedOutflow.width} onChange={handleChange} />
            </label>
          </div>
          <div>
            <label>
              Lot No:
              <input
                type="text"
                name="lotnumber"
                value={editedOutflow.lotnumber}
                onChange={handleChange}
              />
            </label>
          </div>
        </>
      )}
      <div>
        <label>
          Quantity:
          <input
            type="text"
            name="quantity"
            value={editedOutflow.quantity}
            onChange={handleChange}
          />
        </label>
      </div>
      <div>
        <label>
          Price:
          <input type="text" name="price" value={editedOutflow.price} onChange={handleChange} />
        </label>
      </div>
      <div>
      <label>
        Vendor:
        <select name="vendor" value={editedOutflow.vendorname} onChange={handleChange} required>
          <option value="">Select a vendor</option>
          {vendors.map((vendor) => (
            <option key={vendor.vendorid} value={vendor.name}>
              {vendor.name}
            </option>
          ))}
        </select>
      </label>
      </div>
      <div>
        <button onClick={handleSave}>Save</button>
      </div>
    </div>
  );
};

export default EditOutflow;
